import { create } from 'zustand';

export type ArenaStatus = 'leading' | 'risky' | 'losing' | 'neutral';

interface WalletState {
  connected: boolean;
  address: string | null;
  balance: number;
}

interface ArenaState {
  /* Prediction inputs */
  price: number;
  stake: number;
  setPrice: (price: number) => void;
  setStake: (stake: number) => void;

  /* Round metadata */
  currentRound: number;
  roundEndTime: number;
  totalPool: number;
  activeUsers: number;

  /* Strategy */
  status: ArenaStatus;
  setStatus: (status: ArenaStatus) => void;
  multiplier: number;

  /* Wallet (mock) */
  wallet: WalletState;
  connectWallet: () => void;
  disconnectWallet: () => void;

  /* Arena action */
  isEntering: boolean;
  enterArena: () => void;
}

export const useArenaStore = create<ArenaState>((set, get) => ({
  /* Prediction inputs */
  price: 0.1420,
  stake: 500,
  setPrice: (price) => {
    set({ price });
    // Recalculate multiplier based on deviation from current price
    const currentPrice = 0.1430;
    const deviation = Math.abs(price - currentPrice) / currentPrice;
    const multiplier = Math.max(1.1, Math.min(12.0, 1.5 + deviation * 50));
    set({ multiplier: Math.round(multiplier * 10) / 10 });
  },
  setStake: (stake) => set({ stake }),

  /* Round metadata */
  currentRound: 402,
  roundEndTime: Date.now() + 4 * 60 * 60 * 1000 + 12 * 60 * 1000 + 45 * 1000,
  totalPool: 125000,
  activeUsers: 12482,

  /* Strategy */
  status: 'leading',
  setStatus: (status) => set({ status }),
  multiplier: 3.2,

  /* Wallet (mock) */
  wallet: {
    connected: false,
    address: null,
    balance: 0,
  },
  connectWallet: () =>
    set({
      wallet: {
        connected: true,
        address: 'GC72MQYK...45D2',
        balance: 14520.45,
      },
    }),
  disconnectWallet: () =>
    set({
      wallet: {
        connected: false,
        address: null,
        balance: 0,
      },
    }),

  /* Arena action */
  isEntering: false,
  enterArena: () => {
    set({ isEntering: true });
    setTimeout(() => {
      set({ isEntering: false });
    }, 2500);
  },
}));
